  5→//! Saddle command - Return context needed to saddle up on a Heat
  6→
  7→use std::fs;
  8→use std::path::PathBuf;
  9→
 10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 11→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 13→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 14→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
 15→use crate::jjrq_query::jjrq_resolve_default_heat;
 16→use crate::jjrpd_parade::{jjrpd_print_file_bitmap, jjrpd_print_commit_swimlanes};
 17→
 18→/// Arguments for saddle command
 19→#[derive(clap::Args, Debug)]
 20→pub struct jjrsd_SaddleArgs {
 21→    /// Path to the Gallops JSON file
 22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 23→    pub file: PathBuf,
 24→
 25→    /// Target Heat identity (Firemark) or Pace identity (Coronet). If omitted, uses first racing heat.
 26→    pub firemark: Option<String>,
 27→}
 28→
 29→/// Run the saddle command - return Heat context
 30→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> i32 {
 31→    let gallops = match Gallops::jjrg_load(&args.file) {
 32→        Ok(g) => g,
 33→        Err(e) => {
 34→            eprintln!("jjx_orient: error: {}", e);
 35→            return 1;
 36→        }
 37→    };
 38→
 39→    // Collect racing heats in heat_order priority sequence for display table
 40→    {
 41→        let racing_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heat_order.iter()
 42→            .filter_map(|fm| gallops.heats.get(fm).map(|h| (fm, h)))
 43→            .filter(|(_, heat)| heat.status == HeatStatus::Racing)
 44→            .collect();
 45→
 46→        if !racing_heats.is_empty() {
 47→            let mut table = jjrp_Table::jjrp_new(vec![
 48→                jjrp_Column::new("₣Fire", jjrp_Align::Left),
 49→                jjrp_Column::new("Silks", jjrp_Align::Left),
 50→                jjrp_Column::new("Status", jjrp_Align::Left),
 51→                jjrp_Column::new("Done", jjrp_Align::Right),
 52→                jjrp_Column::new("Total", jjrp_Align::Right),
 53→            ]);
 54→
 55→            // Measure all rows to compute column widths
 56→            for (key, heat) in &racing_heats {
 57→                let defined_count = heat.paces.values().filter(|pace| {
 58→                    if let Some(tack) = pace.tacks.first() {
 59→                        tack.state != PaceState::Abandoned
 60→                    } else {
 61→                        true
 62→                    }
 63→                }).count();
 64→
 65→                let completed_count = heat.paces.values().filter(|pace| {
 66→                    if let Some(tack) = pace.tacks.first() {
 67→                        tack.state == PaceState::Complete
 68→                    } else {
 69→                        false
 70→                    }
 71→                }).count();
 72→
 73→                table.jjrp_measure(&[
 74→                    key,
 75→                    &heat.silks,
 76→                    "racing",
 77→                    &completed_count.to_string(),
 78→                    &defined_count.to_string(),
 79→                ]);
 80→            }
 81→
 82→            // Print header and separator
 83→            println!("Racing-heats:");
 84→            table.jjrp_print_header();
 85→            table.jjrp_print_separator();
 86→
 87→            // Print data rows
 88→            for (key, heat) in &racing_heats {
 89→                let defined_count = heat.paces.values().filter(|pace| {
 90→                    if let Some(tack) = pace.tacks.first() {
 91→                        tack.state != PaceState::Abandoned
 92→                    } else {
 93→                        true
 94→                    }
 95→                }).count();
 96→
 97→                let completed_count = heat.paces.values().filter(|pace| {
 98→                    if let Some(tack) = pace.tacks.first() {
 99→                        tack.state == PaceState::Complete
100→                    } else {
101→                        false
102→                    }
103→                }).count();
104→
105→                table.jjrp_print_row(&[
106→                    key,
107→                    &heat.silks,
108→                    "racing",
109→                    &completed_count.to_string(),
110→                    &defined_count.to_string(),
111→                ]);
112→            }
113→
114→            println!();
115→        }
116→    }
117→
118→    // Resolve firemark: use provided value or auto-select first racing heat
119→    let firemark_str = match args.firemark {
120→        Some(fm) => fm,
121→        None => {
122→            match jjrq_resolve_default_heat(&gallops) {
123→                Ok(fm) => fm,
124→                Err(e) => {
125→                    eprintln!("jjx_orient: error: {}", e);
126→                    return 1;
127→                }
128→            }
129→        }
130→    };
131→
132→    // Detect if input is a coronet (5 chars) or firemark (2 chars)
133→    // Strip any prefix first: ₣ (U+20A3) or ₢ (U+20A2)
134→    let stripped_input = firemark_str
135→        .trim_start_matches('₣')
136→        .trim_start_matches('₢');
137→
138→    let target_coronet = if stripped_input.len() == 5 {
139→        // It's a coronet - parse to get parent firemark
140→        let coronet = match Coronet::jjrf_parse(&firemark_str) {
141→            Ok(c) => c,
142→            Err(e) => {
143→                eprintln!("jjx_orient: error: {}", e);
144→                return 1;
145→            }
146→        };
147→        Some(coronet)
148→    } else if stripped_input.len() == 2 {
149→        // It's a firemark - existing behavior
150→        None
151→    } else {
152→        eprintln!("jjx_orient: error: Invalid argument '{}' (must be 2-char firemark or 5-char coronet)", firemark_str);
153→        return 1;
154→    };
155→
156→    // Extract firemark (either directly provided or from coronet parent)
157→    let firemark = if let Some(ref coronet) = target_coronet {
158→        coronet.jjrf_parent_firemark()
159→    } else {
160→        match Firemark::jjrf_parse(&firemark_str) {
161→            Ok(fm) => fm,
162→            Err(e) => {
163→                eprintln!("jjx_orient: error: {}", e);
164→                return 1;
165→            }
166→        }
167→    };
168→
169→    let heat_key = firemark.jjrf_display();
170→    let heat = match gallops.heats.get(&heat_key) {
171→        Some(h) => h,
172→        None => {
173→            eprintln!("jjx_orient: error: Heat '{}' not found", heat_key);
174→            return 1;
175→        }
176→    };
177→
178→    // Check if heat is stabled (cannot saddle stabled heat)
179→    if heat.status == HeatStatus::Stabled {
180→        eprintln!("jjx_orient: error: Cannot saddle stabled heat '{}'", heat_key);
181→        return 1;
182→    }
183→
184→    // Read paddock file content
185→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
186→        Ok(content) => content,
187→        Err(e) => {
188→            eprintln!("jjx_orient: error reading paddock file '{}': {}", heat.paddock_file, e);
189→            return 1;
190→        }
191→    };
192→
193→    // Get recent steeplechase entries
194→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
195→        firemark: firemark.jjrf_as_str().to_string(),
196→        limit: 10,
197→    }).unwrap_or_default();
198→
199→    // Find pace to display
200→    let mut pace_coronet: Option<String> = None;
201→    let mut pace_silks: Option<String> = None;
202→    let mut pace_state: Option<String> = None;
203→    let mut spec: Option<String> = None;
204→    let mut direction: Option<String> = None;
205→
206→    if let Some(ref coronet) = target_coronet {
207→        // Specific coronet requested - look it up directly
208→        let coronet_key = coronet.jjrf_display();
209→
210→        match heat.paces.get(&coronet_key) {
211→            Some(pace) => {
212→                if let Some(tack) = pace.tacks.first() {
213→                    match tack.state {
214→                        PaceState::Rough | PaceState::Bridled => {
215→                            pace_coronet = Some(coronet_key.clone());
216→                            pace_silks = Some(tack.silks.clone());
217→                            pace_state = Some(match tack.state {
218→                                PaceState::Rough => "rough".to_string(),
219→                                PaceState::Bridled => "bridled".to_string(),
220→                                _ => unreachable!(),
221→                            });
222→                            spec = Some(tack.text.clone());
223→                            if tack.state == PaceState::Bridled {
224→                                direction = tack.direction.clone();
225→                            }
226→                        }
227→                        PaceState::Complete => {
228→                            eprintln!("jjx_orient: error: Pace '{}' is already complete", coronet_key);
229→                            return 1;
230→                        }
231→                        PaceState::Abandoned => {
232→                            eprintln!("jjx_orient: error: Pace '{}' is abandoned", coronet_key);
233→                            return 1;
234→                        }
235→                        _ => {
236→                            eprintln!("jjx_orient: error: Pace '{}' has invalid state", coronet_key);
237→                            return 1;
238→                        }
239→                    }
240→                } else {
241→                    eprintln!("jjx_orient: error: Pace '{}' has no tacks", coronet_key);
242→                    return 1;
243→                }
244→            }
245→            None => {
246→                eprintln!("jjx_orient: error: Pace '{}' not found in heat '{}'", coronet_key, heat_key);
247→                return 1;
248→            }
249→        }
250→    } else {
251→        // Find first actionable pace (rough or bridled)
252→        for coronet_key in &heat.order {
253→            if let Some(pace) = heat.paces.get(coronet_key) {
254→                if let Some(tack) = pace.tacks.first() {
255→                    match tack.state {
256→                        PaceState::Rough | PaceState::Bridled => {
257→                            pace_coronet = Some(coronet_key.clone());
258→                            pace_silks = Some(tack.silks.clone());
259→                            pace_state = Some(match tack.state {
260→                                PaceState::Rough => "rough".to_string(),
261→                                PaceState::Bridled => "bridled".to_string(),
262→                                _ => unreachable!(),
263→                            });
264→                            spec = Some(tack.text.clone());
265→                            if tack.state == PaceState::Bridled {
266→                                direction = tack.direction.clone();
267→                            }
268→                            break;
269→                        }
270→                        _ => continue,
271→                    }
272→                }
273→            }
274→        }
275→    }
276→
277→    // Determine heat status string
278→    let status_str = match heat.status {
279→        HeatStatus::Racing => "racing",
280→        HeatStatus::Stabled => "stabled",
281→        HeatStatus::Retired => "retired",
282→    };
283→
284→    // Output plain text format
285→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
286→    println!("Paddock: {}", heat.paddock_file);
287→    println!();
288→    println!("Paddock-content:");
289→    for line in paddock_content.lines() {
290→        println!("  {}", line);
291→    }
292→    println!();
293→
294→    if let Some(coronet) = pace_coronet {
295→        if let Some(silks) = pace_silks {
296→            if let Some(state) = pace_state {
297→                println!("Next: {} ({}) [{}]", silks, coronet, state);
298→                println!();
299→                if let Some(spec_text) = spec {
300→                    println!("Docket:");
301→                    for line in spec_text.lines() {
302→                        println!("  {}", line);
303→                    }
304→                    println!();
305→                }
306→                if let Some(dir_text) = direction {
307→                    println!("Warrant:");
308→                    for line in dir_text.lines() {
309→                        println!("  {}", line);
310→                    }
311→                    println!();
312→                }
313→                eprintln!();
314→                if state == "bridled" {
315→                    eprintln!("Recommended: /jjc-heat-mount {} to execute", firemark.jjrf_as_str());
316→                } else {
317→                    eprintln!("Recommended: /jjc-pace-bridle {} or /jjc-heat-mount {}", coronet, firemark.jjrf_as_str());
318→                }
319→            }
320→        }
321→    }
322→
323→    // Output recent work table
324→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
325→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
326→        if let Some(ref action) = entry.action {
327→            action == "n" || action == "A" || action == "d"
328→        } else {
329→            false
330→        }
331→    }).collect();
332→
333→    if !filtered_work.is_empty() {
334→        println!("Recent-work:");
335→
336→        let mut table = jjrp_Table::jjrp_new(vec![
337→            jjrp_Column::new("Commit", jjrp_Align::Left),
338→            jjrp_Column::new("Identity", jjrp_Align::Left),
339→            jjrp_Column::new("Subject", jjrp_Align::Left),
340→        ]);
341→
342→        // Measure all rows to compute column widths
343→        for entry in &filtered_work {
344→            let identity_str = if let Some(ref coronet) = entry.coronet {
345→                coronet.clone()
346→            } else {
347→                heat_key.clone()
348→            };
349→            table.jjrp_measure(&[
350→                &entry.commit,
351→                &identity_str,
352→                &entry.subject,
353→            ]);
354→        }
355→
356→        // Print header and separator
357→        table.jjrp_print_header();
358→        table.jjrp_print_separator();
359→
360→        // Print data rows
361→        for entry in &filtered_work {
362→            let identity_str = if let Some(ref coronet) = entry.coronet {
363→                coronet.clone()
364→            } else {
365→                heat_key.clone()
366→            };
367→            table.jjrp_print_row(&[
368→                &entry.commit,
369→                &identity_str,
370→                &entry.subject,
371→            ]);
372→        }
373→    }
374→
375→    // Always show file-touch bitmap and commit swim lanes after recent work
376→    jjrpd_print_file_bitmap(&firemark, heat);
377→    jjrpd_print_commit_swimlanes(&firemark, heat);
378→
379→    // Call invitatory to check/create officium marker
380→    if let Err(e) = vvc::vvcp_invitatory().await {
381→        eprintln!("jjx_orient: warning: invitatory failed: {}", e);
382→    }
383→
384→    0
385→}
