365→/// Format the file-touch bitmap for a heat as a String.
366→///
367→/// Uses shared query routines from jjrq_query to get file touches,
368→/// then formats as a bitmap with columns per pace and rows per file,
369→/// grouped by identical touch patterns.
370→pub fn jjrpd_format_file_bitmap(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
371→    let touches = jjrq_file_touches_for_heat(firemark.jjrf_as_str())?;
372→
373→    let has_heat_level = !touches.heat_files.is_empty();
374→
375→    // Build pace columns: only paces with commits, in heat order
376→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
377→    for coronet_key in &heat.order {
378→        if !touches.coronets_with_commits.contains(coronet_key) {
379→            continue;
380→        }
381→        if let Some(pace) = heat.paces.get(coronet_key) {
382→            if let Some(tack) = pace.tacks.first() {
383→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
384→                if let Some(ch) = raw.chars().last() {
385→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
386→                }
387→            }
388→        }
389→    }
390→
391→    // Map coronet_display -> column index
392→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
393→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
394→        coronet_to_col.insert(coronet_display.clone(), idx);
395→    }
396→
397→    let heat_col_idx = pace_columns.len();
398→    let total_cols = if has_heat_level { heat_col_idx + 1 } else { heat_col_idx };
399→
400→    // Build file -> touch vector from the shared query result
401→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
402→
403→    for (coronet, files) in &touches.pace_files {
404→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
405→            for filename in files {
406→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
407→                if col_idx < row.len() {
408→                    row[col_idx] = true;
409→                }
410→            }
411→        }
412→    }
413→
414→    if has_heat_level {
415→        for filename in &touches.heat_files {
416→            let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
417→            if heat_col_idx < row.len() {
418→                row[heat_col_idx] = true;
419→            }
420→        }
421→    }
422→
423→    let mut output = String::new();
424→
425→    if file_touches_map.is_empty() {
426→        writeln!(output, "File-touch bitmap: (no work file changes)").unwrap();
427→        return Ok(output);
428→    }
429→
430→    // Group files by identical touch pattern
431→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
432→    for (filename, pattern) in &file_touches_map {
433→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
434→    }
435→
436→    for files in pattern_groups.values_mut() {
437→        files.sort();
438→    }
439→
440→    // Header
441→    writeln!(output, "File-touch bitmap (x = pace commit touched file):").unwrap();
442→    writeln!(output).unwrap();
443→
444→    // Vertical legend
445→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
446→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
447→    }
448→    if has_heat_level {
449→        writeln!(output, "  {} * heat-level", pace_columns.len() + 1).unwrap();
450→    }
451→    writeln!(output).unwrap();
452→
453→    // Column header line (terminal chars aligned with bitmap positions)
454→    let mut header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
455→    if has_heat_level {
456→        header_chars.push('*');
457→    }
458→    let header_line: String = header_chars.iter().collect();
459→    writeln!(output, "{}", header_line).unwrap();
460→
461→    // Sort patterns: more touches first, then lexicographic
462→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
463→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
464→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
465→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
466→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
467→    });
468→
469→    for (pattern, files) in &sorted_patterns {
470→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
471→        writeln!(output, "{} {}", bitmap, files.join(", ")).unwrap();
472→    }
473→
474→    Ok(output)
475→}
