505→/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
506→fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
507→    match index {
508→        0..=8 => Some((b'1' + index as u8) as char),
509→        9..=34 => Some((b'a' + (index - 9) as u8) as char),
510→        35..=60 => Some((b'A' + (index - 35) as u8) as char),
511→        _ => None,
512→    }
513→}
