515→/// Format commit swim lanes for a heat as a String: paces × commits matrix.
516→///
517→/// Shows when work happened on each pace and how work interleaved.
518→pub fn jjrpd_format_commit_swimlanes(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
519→    let rein_args = jjrs_ReinArgs {
520→        firemark: firemark.jjrf_as_str().to_string(),
521→        limit: 10000,
522→    };
523→
524→    let entries = jjrs_get_entries(&rein_args)?;
525→
526→    if entries.is_empty() {
527→        return Ok(String::new());
528→    }
529→
530→    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
531→    let total_commits = entries.len();
532→    let max_commits: usize = 35;
533→    let truncated = total_commits > max_commits;
534→    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
535→        .iter()
536→        .take(max_commits)
537→        .collect::<Vec<_>>()
538→        .into_iter()
539→        .rev()
540→        .collect();
541→
542→    // Build pace rows: ordered by first chronological appearance
543→    let mut pace_order: Vec<(String, char, String)> = Vec::new(); // (coronet_display, term_char, silks)
544→    let mut pace_index: BTreeMap<String, usize> = BTreeMap::new();
545→    let mut has_heat_level = false;
546→
547→    for entry in &display_entries {
548→        if let Some(ref coronet) = entry.coronet {
549→            if !pace_index.contains_key(coronet) {
550→                let idx = pace_order.len();
551→                let raw = coronet.strip_prefix('₢').unwrap_or(coronet);
552→                let ch = raw.chars().last().unwrap_or('?');
553→                let silks = heat.paces.get(coronet)
554→                    .and_then(|p| p.tacks.first())
555→                    .map(|t| t.silks.clone())
556→                    .unwrap_or_else(|| "unknown".to_string());
557→                pace_index.insert(coronet.clone(), idx);
558→                pace_order.push((coronet.clone(), ch, silks));
559→            }
560→        } else {
561→            has_heat_level = true;
562→        }
563→    }
564→
565→    let total_rows = pace_order.len() + if has_heat_level { 1 } else { 0 };
566→    let heat_row_idx = pace_order.len();
567→
568→    if total_rows == 0 {
569→        return Ok(String::new());
570→    }
571→
572→    // Build bitmap: rows × columns
573→    let num_cols = display_entries.len();
574→    let mut bitmap: Vec<Vec<bool>> = vec![vec![false; num_cols]; total_rows];
575→    let mut row_commit_counts: Vec<usize> = vec![0; total_rows];
576→
577→    for (col, entry) in display_entries.iter().enumerate() {
578→        if let Some(ref coronet) = entry.coronet {
579→            if let Some(&row) = pace_index.get(coronet) {
580→                bitmap[row][col] = true;
581→                row_commit_counts[row] += 1;
582→            }
583→        } else if has_heat_level {
584→            bitmap[heat_row_idx][col] = true;
585→            row_commit_counts[heat_row_idx] += 1;
586→        }
587→    }
588→
589→    let mut output = String::new();
590→
591→    writeln!(output).unwrap();
592→    writeln!(output, "Commit swim lanes (x = commit affiliated with pace):").unwrap();
593→    writeln!(output).unwrap();
594→
595→    if truncated {
596→        writeln!(output, "(showing last {} of {} commits)", max_commits, total_commits).unwrap();
597→        writeln!(output).unwrap();
598→    }
599→
600→    // Vertical legend
601→    for (i, (_, ch, silks)) in pace_order.iter().enumerate() {
602→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
603→    }
604→    if has_heat_level {
605→        writeln!(output, "  {} * heat-level", pace_order.len() + 1).unwrap();
606→    }
607→    writeln!(output).unwrap();
608→
609→    // Column header line
610→    let header: String = (0..num_cols).filter_map(zjjrpd_commit_index_char).collect();
611→    writeln!(output, "{}", header).unwrap();
612→
613→    // Bitmap rows
614→    for row in 0..total_rows {
615→        let bits: String = bitmap[row].iter().map(|&b| if b { 'x' } else { '·' }).collect();
616→        let (term_char, count) = if row < pace_order.len() {
617→            (pace_order[row].1, row_commit_counts[row])
618→        } else {
619→            ('*', row_commit_counts[row])
620→        };
621→        writeln!(output, "{}  {}  {}c", bits, term_char, count).unwrap();
622→    }
623→
624→    Ok(output)
625→}
