635→/// Print files-per-commit bitmap for a single pace.
636→///
637→/// Shows which files each commit in this pace touched.
638→/// Called after tack history in pace parade.
639→fn zjjrpd_print_pace_commits(firemark: &Firemark, coronet_key: &str) {
640→    let rein_args = jjrs_ReinArgs {
641→        firemark: firemark.jjrf_as_str().to_string(),
642→        limit: 10000,
643→    };
644→
645→    let entries = match jjrs_get_entries(&rein_args) {
646→        Ok(e) => e,
647→        Err(e) => {
648→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
649→            return;
650→        }
651→    };
652→
653→    // Filter by coronet, then reverse for chronological order
654→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
655→        .iter()
656→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
657→        .collect::<Vec<_>>()
658→        .into_iter()
659→        .rev()
660→        .collect();
661→
662→    if pace_entries.is_empty() {
663→        return;
664→    }
665→
666→    // Get files for each commit
667→    let num_commits = pace_entries.len();
668→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
669→
670→    for (col, entry) in pace_entries.iter().enumerate() {
671→        let files = zjjrq_files_for_commit(&entry.commit);
672→        for path in files {
673→            if zjjrq_is_infra_file(&path) {
674→                continue;
675→            }
676→            let bare = zjjrq_bare_filename(&path);
677→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
678→            row[col] = true;
679→        }
680→    }
681→
682→    if file_touches.is_empty() {
683→        println!();
684→        println!("Pace commits: (no project file commits)");
685→        return;
686→    }
687→
688→    println!();
689→    println!("Pace commits (x = commit touched file):");
690→    println!();
691→
692→    // Legend: commit index char, SHA, subject
693→    for (i, entry) in pace_entries.iter().enumerate() {
694→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
695→        println!("  {} {}  {}", ch, entry.commit, entry.subject);
696→    }
697→    println!();
698→
699→    // Column header line
700→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
701→    println!("{}", header);
702→
703→    // Group by identical touch pattern
704→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
705→    for (filename, pattern) in &file_touches {
706→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
707→    }
708→    for files in pattern_groups.values_mut() {
709→        files.sort();
710→    }
711→
712→    // Sort: more touches first, then lexicographic
713→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
714→    sorted.sort_by(|(a, _), (b, _)| {
715→        let ca: usize = a.iter().filter(|&&v| v).count();
716→        let cb: usize = b.iter().filter(|&&v| v).count();
717→        cb.cmp(&ca).then_with(|| a.cmp(b))
718→    });
719→
720→    for (pattern, files) in &sorted {
721→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
722→        println!("{} {}", bits, files.join(", "));
723→    }
724→}
