102→/// Get all steeplechase entries for a heat with file touch data per commit.
103→///
104→/// Returns entries plus a mapping of coronet -> set of bare work filenames.
105→/// Also returns heat-level (no coronet) work files separately.
106→/// Used by the file-touch bitmap visualization.
107→pub fn jjrq_file_touches_for_heat(firemark_raw: &str) -> Result<jjrq_HeatFileTouches, String> {
108→    let rein_args = jjrs_ReinArgs {
109→        firemark: firemark_raw.to_string(),
110→        limit: 10000,
111→    };
112→
113→    let entries = jjrs_get_entries(&rein_args)?;
114→
115→    let mut pace_files: std::collections::BTreeMap<String, std::collections::BTreeSet<String>> = std::collections::BTreeMap::new();
116→    let mut heat_files: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
117→    let mut coronets_seen: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
118→
119→    for entry in &entries {
120→        let commit_files: Vec<String> = zjjrq_files_for_commit(&entry.commit)
121→            .into_iter()
122→            .filter(|p| !zjjrq_is_infra_file(p))
123→            .map(|p| zjjrq_bare_filename(&p))
124→            .collect();
125→
126→        if let Some(ref coronet) = entry.coronet {
127→            coronets_seen.insert(coronet.clone());
128→            let set = pace_files.entry(coronet.clone()).or_default();
129→            for f in commit_files {
130→                set.insert(f);
131→            }
132→        } else {
133→            for f in commit_files {
134→                heat_files.insert(f);
135→            }
136→        }
137→    }
138→
139→    Ok(jjrq_HeatFileTouches {
140→        pace_files,
141→        heat_files,
142→        coronets_with_commits: coronets_seen,
143→    })
144→}
